import java.nio.ByteBuffer;
import java.util.Scanner;

public class SecureBuffer {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter a string: ");
        String userInput = scanner.nextLine();

        // Define maximum buffer size to prevent buffer overflow
        int maxBufferSize = 10;

        // Validate user input length against the maximum buffer size
        if (userInput.length() > maxBufferSize) {
            System.out.println("Input exceeds maximum buffer size. Please enter a shorter string.");
            return;
        }

        // Use ByteBuffer with specified capacity to prevent buffer overflow
        ByteBuffer buffer = ByteBuffer.allocate(maxBufferSize);

        // Copy userInput into the buffer safely
        buffer.put(userInput.getBytes());

        System.out.println("Buffer contents: " + new String(buffer.array()).trim());
    }
}

### Explanation:
취약유형: Buffer Overflow
